import { useEffect, useState } from "react"

import CelulaBrinquedo from "../CelulaBrinquedo";
import { FetchApi } from "../../../Controller/FetchApi";

export default function TelaBrinquedos(){
    const [brinquedos, setBrinquedos] = useState([]);

    useEffect(() => {
        async function listarBrinquedos(){
            setBrinquedos(await FetchApi.consultaGet('/brinquedos').brinquedo.resultado);
        }
        listarBrinquedos();
        
    }, []);

    return(
        <div className="row">
            <CelulaBrinquedo indice={0} brinquedo={brinquedos[0]} />
        </div>
    )
}
